import Navbar from "./Navbar";

const Layout = ({ children }) => (
  <>
    <style>{style}</style>
    <div className='wrapper'>
      <Title />
      <Navbar />
      <div>
        {children}
      </div>
    </div>
  </>
);

const style = `
  * {
    font-family:Roboto;
  }
  ol {
      padding-left:1rem;
  }
  .wrapper {
    width:70vw;
    margin:auto;
  }
`;

export default Layout;

const Title = () => (
  <div>
    <h1 className="title">Wenuwake</h1>
    <div className="sub-title">Portfolio website of Jithin KS</div>
  </div>
);
